#!/usr/bin/env node
/**
 * DeepSeek Web 单账号登录 + token 提取
 * 
 * 登录流程：
 *  1. 创建新 camo profile（无 cookie 残留）
 *  2. 打开登录页，输入邮箱密码，点击登录
 *  3. 等待登录成功（遇风控暂停等用户处理，遇绑定手机号自动点跳过）
 *  4. 提取 localStorage.userToken 保存到 auth 目录
 * 
 * Usage:
 *   node login-deepseek.mjs --email <email> --password <pw> --alias <alias> [--token-dir <dir>]
 */

import { execSync } from 'node:child_process';
import { writeFileSync } from 'node:fs';

function sh(cmd) { return execSync(cmd, { encoding: 'utf8', stdio: ['pipe', 'pipe', 'pipe'] }).trim(); }
function shJson(cmd) { return JSON.parse(sh(cmd)); }

const args = process.argv.slice(2);
function getArg(name) { const idx = args.indexOf(`--${name}`); return idx >= 0 ? args[idx + 1] : null; }

const EMAIL = getArg('email');
const PASSWORD = [REDACTED]'password');
const ALIAS = getArg('alias');
const TOKEN_DIR = getArg('token-dir') || '/Volumes/extension/.rcc/auth';

if (!EMAIL || !PASSWORD || !ALIAS) {
  console.error('Usage: login-deepseek.mjs --email <email> --password <pw> --alias <alias> [--token-dir <dir>]');
  process.exit(1);
}

const PROFILE = `deepseek-${ALIAS}`;
const LOGIN_URL = 'https://chat.deepseek.com/sign_in';
const HOME_URL = 'https://chat.deepseek.com/';
const TOKEN_FILE = `${TOKEN_DIR}/deepseek-${ALIAS}.json`;
const POLL_MS = 2000;
const MAX_WAIT = 240000;         // 无风控：最多等 2 分钟
const CHALLENGE_WAIT = 900000;   // 有风控：最多等 10 分钟
const LOAD_TIMEOUT = 40000;      // 页面加载超时
const LOAD_RETRY = 5;            // 页面加载重试次数

function sleep(ms) { return new Promise(r => setTimeout(r, ms)); }

/** 检测是否遇到风控/验证码 */
function isChallenge(text) {
  return /captcha|hcaptcha|验证|verification|challenge|滑块|turnstile/i.test(text || '');
}

/** 尝试点击"跳过"按钮（绑定手机号弹窗） */
function trySkipBinding(profile) {
  try {
    const clicked = shJson(`camo devtools eval ${profile} "(function(){var btns=Array.from(document.querySelectorAll('button,a'));var skip=btns.find(b=>(b.innerText||'').match(/跳过|skip|稍后|later|暂不|maybe later|not now/i));if(skip){skip.click();return 'clicked:'+skip.innerText.trim();}return 'not_found';})()"`);
    return clicked.result?.value || 'not_found';
  } catch { return 'error'; }
}

/** 等待页面加载，失败则重试 */
async function waitForPageLoad(profile) {
  for (let attempt = 0; attempt < LOAD_RETRY; attempt++) {
    const deadline = Date.now() + LOAD_TIMEOUT;
    while (Date.now() < deadline) {
      await sleep(1000);
      try {
        const url = shJson(`camo devtools eval ${profile} "document.location.href"`).result?.value;
        if (url && url !== 'about:blank') {
          const inputCount = shJson(`camo devtools eval ${profile} "document.querySelectorAll('input').length"`).result?.value;
          if (inputCount > 0) return true;
        }
      } catch {}
    }
    console.log(`[${ALIAS}] 页面加载超时，第 ${attempt + 1}/${LOAD_RETRY} 次重试 ...`);
    try { sh(`camo stop ${PROFILE}`); } catch {}
    await sleep(2000);
    try { sh(`camo start ${PROFILE} --url "${LOGIN_URL}" --no-headless`); } catch {}
    await sleep(4000);
  }
  return false;
}

/** 等待登录成功，含风控等待 + 自动跳过绑定手机号 */
async function waitForLogin(profile) {
  const start = Date.now();
  let token = null;
  let challengeSeen = false;

  while (true) {
    const elapsed = Date.now() - start;
    if (elapsed > (challengeSeen ? CHALLENGE_WAIT : MAX_WAIT)) break;
    await sleep(POLL_MS);

    // 读取 URL
    let url = '';
    try { url = shJson(`camo devtools eval ${profile} "document.location.href"`).result?.value || ''; } catch {}

    // URL 已跳转到首页 → 检查 token
    if (url === HOME_URL || url === HOME_URL.replace(/\/$/, '')) {
      // 尝试关闭"绑定手机号"弹窗
      const skipped = trySkipBinding(profile);
      if (skipped.startsWith('clicked')) {
        console.log(`[${ALIAS}] ℹ️  已跳过手机号绑定弹窗: ${skipped}`);
        await sleep(2000);
      }

      try {
        const raw = shJson(`camo devtools eval ${profile} "localStorage.getItem('userToken')"`).result?.value;
        if (raw && raw !== 'null') {
          const parsed = JSON.parse(raw);
          if (parsed.value) { token = parsed.value; break; }
        }
      } catch {}
    }

    // 检测风控
    let pageText = '';
    try { pageText = shJson(`camo devtools eval ${profile} "document.body.innerText.substring(0, 2000)"`).result?.value || ''; } catch {}
    if (isChallenge(pageText)) {
      if (!challengeSeen) {
        challengeSeen = true;
        console.log(`[${ALIAS}] ⚠️  检测到风控/验证码，请在浏览器中手动完成 ...`);
      }
    }
  }

  return token;
}

async function main() {
  console.log(`[${ALIAS}] 开始登录 ${EMAIL} ...`);

  // 1. 准备全新 profile（删除旧的，确保无 cookie 残留）
  console.log(`[${ALIAS}] 准备全新 profile: ${PROFILE}`);
  try { sh(`camo stop ${PROFILE}`); } catch {}
  await sleep(1000);
  try { sh(`camo profile delete ${PROFILE}`); } catch {}
  sh(`camo profile create ${PROFILE}`);

  // 2. 启动浏览器
  console.log(`[${ALIAS}] 启动浏览器 ...`);
  sh(`camo start ${PROFILE} --url "${LOGIN_URL}" --no-headless`);
  await sleep(4000);

  // 等待页面加载完成，失败则重试
  const loaded = await waitForPageLoad(PROFILE);
  if (!loaded) {
    console.error(`[${ALIAS}] ❌ 登录页加载失败`);
    try { sh(`camo stop ${PROFILE}`); } catch {}
    process.exit(1);
  }

  const url = shJson(`camo devtools eval ${PROFILE} "document.location.href"`).result?.value;
  console.log(`[${ALIAS}] 当前 URL: ${url}`);

  // 3. 输入邮箱
  console.log(`[${ALIAS}] 输入邮箱 ...`);
  sh(`camo click ${PROFILE} --selector "input[type=text]"`);
  await sleep(500);
  sh(`camo type ${PROFILE} "input[type=text]" "${EMAIL}"`);
  await sleep(1000);

  let emailVal = shJson(`camo devtools eval ${PROFILE} "document.querySelector('input[type=text]').value"`).result?.value;
  if (emailVal !== EMAIL) {
    console.error(`[${ALIAS}] ❌ 邮箱验证失败: 期望 "${EMAIL}", 实际 "${emailVal}"`);
    try { sh(`camo stop ${PROFILE}`); } catch {}
    process.exit(1);
  }
  console.log(`[${ALIAS}] ✅ 邮箱验证通过`);

  // 4. 输入密码
  console.log(`[${ALIAS}] 输入密码 ...`);
  sh(`camo click ${PROFILE} --selector "input[type=password]"`);
  await sleep(500);
  sh(`camo type ${PROFILE} "input[type=password]" "${PASSWORD}"`);
  await sleep(1000);

  let pwCheck = shJson(`camo devtools eval ${PROFILE} "(function(){var p=document.querySelector('input[type=password]');return p&&p.value.length>0?'ok':'empty';})()"`);
  if (pwCheck.result?.value !== 'ok') {
    console.error(`[${ALIAS}] ❌ 密码验证失败`);
    try { sh(`camo stop ${PROFILE}`); } catch {}
    process.exit(1);
  }
  console.log(`[${ALIAS}] ✅ 密码验证通过`);

  // 5. 点击登录
  console.log(`[${ALIAS}] 点击登录 ...`);
  sh(`camo click ${PROFILE} --selector "button.ds-basic-button--primary"`);
  console.log(`[${ALIAS}] 等待登录跳转（遇风控会暂停等用户处理，遇绑定手机号会自动跳过）...`);

  // 6. 等待登录成功
  const token = await waitForLogin(PROFILE);

  if (!token) {
    console.error(`[${ALIAS}] ❌ 登录超时或 token 提取失败`);
    try { sh(`camo stop ${PROFILE}`); } catch {}
    process.exit(1);
  }

  console.log(`[${ALIAS}] ✅ 登录成功, token: ${token.substring(0, 20)}...`);

  // 7. 保存 token
  const now = new Date().toISOString();
  writeFileSync(TOKEN_FILE, JSON.stringify({
